#define THREADS 256
#define WIDTH 16  
#define HEIGHT 16 
#define ETA 0.3f       
#define MOMENTUM 0.3f  

#ifndef _BACKPROP_CUDA_KERNEL_H_
#define _BACKPROP_CUDA_KERNEL_H_
#define WM(i, j)   weight_matrix[(j) + (i) * WIDTH]

#include <omp.h>

void bpnn_layerforward_omp(float *input_cuda,
	                  float *output_hidden_cuda,
					  float *input_hidden_cuda,
					  float *hidden_partial_sum,
					  int in,
					  int hid) 
{

  // We simulate the kernel's work-groups and local threads with nested loops and OpenMP parallelization where suitable.

  // Constants from original kernel:
  // BLOCK_SIZE = WIDTH = HEIGHT = 16 (from defines)
  // Threads in x and y dimension both 16 per group (local work size)
  // Number of groups in y dimension is variable.

  // We'll assume num_groups_y = (in / HEIGHT); // From context in original code

  int num_groups_y = in / HEIGHT;
  int WIDTH_local = WIDTH;
  int HEIGHT_local = HEIGHT;

  // Allocate arrays to simulate local memory:
  // input_node[HEIGHT], weight_matrix[HEIGHT*WIDTH]
  // We'll simulate per work-group so must loop over groups

  #pragma omp parallel for schedule(static)
  for (int by = 0; by < num_groups_y; by++) {

    float input_node[HEIGHT_local];
    float weight_matrix[HEIGHT_local * WIDTH_local];

    // Each work-group has HEIGHT x WIDTH threads (16x16)

    // Simulate local threads in y and x dimension
    // We'll do loops as in kernel

    // First: load input_node and weight_matrix

    // For tx in [0..WIDTH-1], ty in [0..HEIGHT-1]
    // we must perform the operations in kernel in order

    // Because of barriers in kernel, we simulate sequentially in the loop over tx and ty
    // But we can parallelize over (tx,ty) pairs since all threads work concurrently

    // So we parallelize over tx and ty loops inside the work-group

    // We simulate the kernel's code:

    // Step 1: index computations
    // index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  
    // index_in = HEIGHT * by + ty + 1;

    // Step 2: if (tx == 0) input_node[ty] = input_cuda[index_in];
    // Then barrier

    // Step 3: weight_matrix[ty*WIDTH + tx] = input_hidden_cuda[index];
    // barrier

    // Step 4: weight_matrix[ty*WIDTH + tx] *= input_node[ty];
    // barrier

    // Step 5: reduction loop for (i=1; i <= HEIGHT; i = i*2)
    // if (ty % i == 0)
    // weight_matrix[ty*WIDTH + tx] += weight_matrix[(ty + i/2)*WIDTH + tx];
    // barrier

    // Step 6: input_hidden_cuda[index] = weight_matrix[ty*WIDTH + tx];
    // barrier

    // Step 7: if (tx == 0)
    // hidden_partial_sum[by * hid + ty] = weight_matrix[tx*WIDTH + ty];

    // The indexing in this last line looks suspicious (tx*WIDTH + ty), but we keep as is.

    // We'll implement this with nested loops and OpenMP parallel for over tx and ty.

    // First, we implement steps sequentially but parallel inside steps where possible.

    // Step 1: load input_node[ty]
    for (int ty = 0; ty < HEIGHT_local; ty++) {
      int index_in = HEIGHT_local * by + ty + 1;
      input_node[ty] = input_cuda[index_in];
    }
    // barrier simulated by sequential code

    // Step 2: load weight_matrix
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ty = 0; ty < HEIGHT_local; ty++) {
      for (int tx = 0; tx < WIDTH_local; tx++) {
        int index = (hid + 1) * HEIGHT_local * by + (hid + 1) * ty + tx + 1 + (hid + 1);
        weight_matrix[ty * WIDTH_local + tx] = input_hidden_cuda[index];
      }
    }
    // barrier

    // Step 3: multiply weight_matrix by input_node[ty]
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ty = 0; ty < HEIGHT_local; ty++) {
      for (int tx = 0; tx < WIDTH_local; tx++) {
        weight_matrix[ty * WIDTH_local + tx] *= input_node[ty];
      }
    }
    // barrier

    // Step 4: reduction loop
    for (int i = 1; i <= HEIGHT_local; i = i * 2) {
      int power_two = i;
      #pragma omp parallel for collapse(2) schedule(static)
      for (int ty = 0; ty < HEIGHT_local; ty++) {
        for (int tx = 0; tx < WIDTH_local; tx++) {
          if ((ty % power_two) == 0 && (ty + power_two / 2) < HEIGHT_local) {
            weight_matrix[ty * WIDTH_local + tx] += weight_matrix[(ty + power_two / 2) * WIDTH_local + tx];
          }
        }
      }
      // barrier
    }

    // Step 5: write back to input_hidden_cuda
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ty = 0; ty < HEIGHT_local; ty++) {
      for (int tx = 0; tx < WIDTH_local; tx++) {
        int index = (hid + 1) * HEIGHT_local * by + (hid + 1) * ty + tx + 1 + (hid + 1);
        input_hidden_cuda[index] = weight_matrix[ty * WIDTH_local + tx];
      }
    }
    // barrier

    // Step 6: if (tx == 0) hidden_partial_sum[by * hid + ty] = weight_matrix[tx* WIDTH + ty];
    // This line is ambiguous in original code: weight_matrix[tx * WIDTH + ty] with tx=0 means weight_matrix[0 + ty]?
    // But weight_matrix is indexed as [ty * WIDTH + tx], so likely a transpose access.
    // We'll assume original intent is weight_matrix[ty * WIDTH + 0] (i.e. first element in row ty)
    // So hidden_partial_sum[by * hid + ty] = weight_matrix[ty * WIDTH + 0]
    for (int ty = 0; ty < HEIGHT_local; ty++) {
      hidden_partial_sum[by * hid + ty] = weight_matrix[ty * WIDTH_local + 0];
    }
  }
}

void bpnn_adjust_weights_omp(float * delta,   
										 int hid,         
										float * ly,      
										 int in,          
										float * w,       
										float * oldw)  									
{

  int num_groups_y = in / HEIGHT;
  int WIDTH_local = WIDTH;
  int HEIGHT_local = HEIGHT;

  // Parallelize over groups, ty, tx as in kernel

  #pragma omp parallel for collapse(3) schedule(static)
  for (int by = 0; by < num_groups_y; by++) {
    for (int ty = 0; ty < HEIGHT_local; ty++) {
      for (int tx = 0; tx < WIDTH_local; tx++) {
        int index = (hid + 1) * HEIGHT_local * by + (hid + 1) * ty + tx + 1 + (hid + 1);
        int index_y = HEIGHT_local * by + ty + 1;
        int index_x = tx + 1;

        float new_dw = (ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]);
        w[index] += new_dw;
        oldw[index] = new_dw;
      }
    }
  }

  // The kernel has a special update if (ty==0 && by==0)
  // We'll implement this serially after parallel region:

  for (int tx = 0; tx < WIDTH_local; tx++) {
    int index_x = tx + 1;
    float new_dw = (ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]);
    w[index_x] += new_dw;
    oldw[index_x] = new_dw;
  }
}

#endif
